    # We work backward from the final value to determine the minimum changes needed
    # At each level, we track how many bits would need to be changed to force a certain value at that level
    # We use dynamic programming, where dp[level][bit] is the minimum number of changes needed to achieve 'bit' at the given level

    dp = [[float('inf')] * 2 for _ in range(N + 1)]
    dp[N][original_value] = 0  # No changes needed at the final step

